mapper.update:
UPDATE t_contract
SET status = #{status},
    update_user_id = #{operatorId}
WHERE contract_id IN

    ${item}

mapper.select:
SELECT tc.*,
tct.name as contractTypeName,
r.actual_name AS responsibleUserName,
e.actual_name AS createUserName,
u.actual_name AS updateUserName,
oe.enterprise_name
FROM t_contract tc
LEFT JOIN t_employee r ON r.employee_id = tc.responsible_user_id
LEFT JOIN t_employee e ON e.employee_id = tc.create_user_id
LEFT JOIN t_employee u ON u.employee_id = tc.update_user_id
LEFT JOIN t_contract_type tct ON tct.contract_type_id = tc.contract_type
LEFT JOIN t_oa_enterprise oe ON oe.enterprise_id = tc.enterprise_id

    tc.deleted_flag = #{queryForm.deletedFlag}

        AND tc.enterprise_id = #{queryForm.enterpriseId}


        AND (INSTR(tc.contract_code,#{queryForm.keywords}) OR INSTR(tc.contract_name,#{queryForm.keywords}) OR
        INSTR(tc.order_no,#{queryForm.keywords}) OR INSTR(oe.enterprise_name,#{queryForm.keywords}))


        AND DATE_FORMAT(tc.create_time, '%Y-%m-%d') >= #{queryForm.createStartTime}


        AND DATE_FORMAT(tc.create_time, '%Y-%m-%d') <= #{queryForm.createEndTime}


        AND tc.status = #{queryForm.status}


        AND tc.signer_type = #{queryForm.signerType}


        AND tc.signer_belong_id = #{queryForm.signerBelongId}


        AND tc.waybill_id = #{queryForm.waybillId}


        AND tc.order_id = #{queryForm.orderId}


        AND tc.contract_type = #{queryForm.contractType}




    ORDER BY tc.create_time DESC
